class Solution:
    def getMaxRepetitions(self, s1: str, n1: int, s2: str, n2: int) -> int:
        if not set(s1) <= set(s2): return 0
        i = j = count = 0
        for _ in range(n1):
            for ch in s1:
                while j < len(s2) and s2[j] != ch:
                    j += 1
                if j == len(s2):
                    count += 1
                    j = 0
                    while j < len(s2) and s2[j] != ch:
                        j += 1
                j += 1
        return count // n2

