class Solution {
public:
    int getMaxRepetitions(string s1, int n1, string s2, int n2) {
        int j=0, cnt=0;
        for(int rep=0; rep<n1; rep++){
            for(char c:s1){
                while(j<(int)s2.size()&&s2[j]!=c) j++;
                if(j==(int)s2.size()){ cnt++; j=0; while(j<(int)s2.size()&&s2[j]!=c) j++; }
                j++;
            }
        }
        return cnt/n2;
    }
};
